const Coverage& Get(Id id, int px) {
    const Coverage* v = kTable[static_cast<int>(id)];
    return px <= 24 ? v[0] : v[1];
}

const char* Name(Id id) { return kNames[static_cast<int>(id)]; }

void ToRgba(const Coverage& cov, uint8_t* dst) {
    const int n = cov.size * cov.size;
    for (int i = 0; i < n; ++i) {
        dst[i * 4 + 0] = 255; dst[i * 4 + 1] = 255;
        dst[i * 4 + 2] = 255; dst[i * 4 + 3] = cov.a8[i];
    }
}

